import { useState } from "react";

function lsGet(key) { try { const v = localStorage.getItem(key); return v ? JSON.parse(v) : null; } catch { return null; } }
function lsSet(key, value) { try { localStorage.setItem(key, JSON.stringify(value)); } catch (e) { console.error(e); } }

const DEFAULT_SETTINGS = {
  shopName: "Unique Books",
  address: "P.O Box 81310 - 80100",
  tillNumber: "5429283",
  phone: "",
  footerText: "Study to shew thyself approved unto God, a workman that needeth not to be ashamed, rightly dividing the word of truth.",
  footerReference: "II Timothy 2:15",
  defaultShipping: 50,
  defaultThreshold: 5,
  invoicePrefix: "",
  logo: null,
};

function getSettings() { const saved = lsGet("ub-settings"); return saved || DEFAULT_SETTINGS; }
function saveSettings(s) { lsSet("ub-settings", s); }

function getCustomers() { return lsGet("ub-customers") || []; }
function saveCustomers(c) { lsSet("ub-customers", c); }

