const DEFAULT_USERS = { admin: { password: "admin123", role: "admin", name: "Shop Owner" }, teller: { password: "teller123", role: "teller", name: "Teller" } };
function getUsers() { const saved = lsGet("ub-users"); return saved || DEFAULT_USERS; }
function saveUsers(users) { lsSet("ub-users", users); }

function LoginScreen({ onLogin, settings }) {
  const [username, setUsername] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");
  function handleLogin() { const users = getUsers(); const user = users[username.toLowerCase()]; if (!user) { setError("User not found"); return; } if (user.password !== password) { setError("Wrong password"); return; } onLogin({ username: username.toLowerCase(), ...user }); }
  return (<div style={{ height:"100vh", display:"flex", alignItems:"center", justifyContent:"center", background:`linear-gradient(135deg,${C.sidebar},${C.blueDark},${C.blue})` }}><div style={{ background:C.white, borderRadius:16, padding:"40px 36px", width:380, boxShadow:"0 20px 60px rgba(0,0,0,0.3)", textAlign:"center" }}>
    <div style={{ width:70, height:70, borderRadius:"50%", background:C.blue, display:"flex", alignItems:"center", justifyContent:"center", margin:"0 auto 16px", color:C.white, fontSize:28, fontWeight:"800", overflow:"hidden" }}>
      {settings.logo ? <img src={settings.logo} alt="Logo" style={{width:"100%",height:"100%",objectFit:"cover"}}/> : "UB"}
    </div>
    <div style={{ fontSize:20, fontWeight:"800", color:C.blueDark, marginBottom:4 }}>{settings.shopName}</div>
    <div style={{ fontSize:12, color:C.muted, marginBottom:24 }}>Management System</div>
    {error && <div style={{ background:"#fee2e2", color:C.red, padding:"8px 14px", borderRadius:7, marginBottom:14, fontSize:13, fontWeight:600 }}>{error}</div>}
    <div style={{ marginBottom:14, textAlign:"left" }}><label style={S.label}>Username</label><input style={S.input} placeholder="Enter username" value={username} onChange={e=>{setUsername(e.target.value);setError("");}} onKeyDown={e=>e.key==="Enter"&&handleLogin()}/></div>
    <div style={{ marginBottom:20, textAlign:"left" }}><label style={S.label}>Password</label><input style={S.input} type="password" placeholder="Enter password" value={password} onChange={e=>{setPassword(e.target.value);setError("");}} onKeyDown={e=>e.key==="Enter"&&handleLogin()}/></div>
    <button style={{...S.btn("primary"),width:"100%",padding:"12px",fontSize:14}} onClick={handleLogin}>🔐 Sign In</button>
  </div></div>);
}

function SettingsPage({ settings, onSave }) {
  const [form, setForm] = useState({ ...settings });
  const [saved, setSaved] = useState(false);
  function handleLogoUpload(e) {
    const file = e.target.files[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (ev) => setForm({ ...form, logo: ev.target.result });
    reader.readAsDataURL(file);
  }
  function handleSave() { onSave(form); setSaved(true); setTimeout(() => setSaved(false), 2000); }
  return (<div>
    <div style={S.pageTitle}>⚙️ Settings</div>
    <div style={S.pageSubtitle}>Customize your bookshop system.</div>
    {saved && <div style={{ background:C.successBg, color:C.success, padding:"10px 16px", borderRadius:8, marginBottom:14, fontWeight:600, fontSize:13 }}>✅ Settings saved successfully!</div>}
    <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:18 }}>
      <div style={S.card}>
        <div style={S.cardTitle}>🏪 Shop Information</div>
        <div style={{ display:"grid", gap:12 }}>
          <div><label style={S.label}>Shop Logo</label>
            <div style={{ display:"flex", alignItems:"center", gap:12 }}>
              <div style={{ width:60, height:60, borderRadius:8, background:C.bg, display:"flex", alignItems:"center", justifyContent:"center", overflow:"hidden", border:`1px solid ${C.border}` }}>
                {form.logo ? <img src={form.logo} alt="Logo" style={{width:"100%",height:"100%",objectFit:"cover"}}/> : <span style={{fontSize:20,color:C.muted}}>UB</span>}
              </div>
              <div>
                <label style={{...S.btn("primary"),cursor:"pointer",margin:0,fontSize:11,padding:"6px 14px"}}>📁 Upload Logo<input type="file" accept="image/*" style={{display:"none"}} onChange={handleLogoUpload}/></label>
                {form.logo && <button style={{...S.btn("danger"),fontSize:11,padding:"6px 14px",marginLeft:6}} onClick={()=>setForm({...form,logo:null})}>Remove</button>}
              </div>
            </div>
          </div>
          <div><label style={S.label}>Shop Name</label><input style={S.input} value={form.shopName} onChange={e=>setForm({...form,shopName:e.target.value})}/></div>
          <div><label style={S.label}>Address</label><input style={S.input} value={form.address} onChange={e=>setForm({...form,address:e.target.value})}/></div>
          <div><label style={S.label}>Phone Number</label><input style={S.input} value={form.phone} onChange={e=>setForm({...form,phone:e.target.value})} placeholder="e.g. 07XX XXX XXX"/></div>
          <div><label style={S.label}>M-Pesa Till Number</label><input style={S.input} value={form.tillNumber} onChange={e=>setForm({...form,tillNumber:e.target.value})}/></div>
        </div>
      </div>
      <div style={S.card}>
        <div style={S.cardTitle}>📄 Invoice Settings</div>
        <div style={{ display:"grid", gap:12 }}>
          <div><label style={S.label}>Invoice Number Prefix</label><input style={S.input} value={form.invoicePrefix} onChange={e=>setForm({...form,invoicePrefix:e.target.value})} placeholder="e.g. INV- or UB-"/></div>
          <div><label style={S.label}>Default Shipping Fee (Ksh)</label><input style={S.input} type="number" value={form.defaultShipping} onChange={e=>setForm({...form,defaultShipping:+e.target.value})}/></div>
          <div><label style={S.label}>Footer Text (Bible Verse)</label><textarea style={{...S.input,height:60,resize:"vertical"}} value={form.footerText} onChange={e=>setForm({...form,footerText:e.target.value})}/></div>
          <div><label style={S.label}>Footer Reference</label><input style={S.input} value={form.footerReference} onChange={e=>setForm({...form,footerReference:e.target.value})} placeholder="e.g. II Timothy 2:15"/></div>
        </div>
      </div>
      <div style={S.card}>
        <div style={S.cardTitle}>📦 Stock Settings</div>
        <div style={{ display:"grid", gap:12 }}>
          <div><label style={S.label}>Default Low Stock Threshold</label><input style={S.input} type="number" min="1" value={form.defaultThreshold} onChange={e=>setForm({...form,defaultThreshold:+e.target.value})}/></div>
        </div>
      </div>
      <div style={{ display:"flex", alignItems:"flex-end" }}><button style={{...S.btn("success"),width:"100%",padding:"14px",fontSize:15}} onClick={handleSave}>💾 Save All Settings</button></div>
    </div>
  </div>);
}

function CustomerPortal({ invoices, customers, onUpdateCustomers }) {
  const [searchClient, setSearchClient] = useState("");
  const [customerData, setCustomerData] = useState(null);
  const [showAddForm, setShowAddForm] = useState(false);
  const [newCustomer, setNewCustomer] = useState({ name: "", phone: "", email: "" });

  const allCustomers = (() => {
    const custMap = {};
    customers.forEach(c => { custMap[c.name] = { ...c, invoices: 0, totalSpent: 0, unpaid: 0, unpaidAmount: 0, lastVisit: "" }; });
    invoices.forEach(inv => {
      if (!custMap[inv.client]) custMap[inv.client] = { name: inv.client, phone: "", email: "", invoices: 0, totalSpent: 0, unpaid: 0, unpaidAmount: 0, lastVisit: "" };
      custMap[inv.client].invoices++;
      custMap[inv.client].totalSpent += inv.items.reduce((s, it) => s + it.qty * it.price, 0) + (inv.shipping || 50);
      if (inv.unpaid) { custMap[inv.client].unpaid++; custMap[inv.client].unpaidAmount += inv.items.reduce((s, it) => s + it.qty * it.price, 0) + (inv.shipping || 50) - (inv.paid || 0); }
      if (inv.date > custMap[inv.client].lastVisit) custMap[inv.client].lastVisit = inv.date;
    });
    return Object.values(custMap).sort((a, b) => b.totalSpent - a.totalSpent);
  })();

  function lookupCustomer() {
    if (!searchClient.trim()) { setCustomerData(null); return; }
    const invs = invoices.filter(inv => inv.client.toLowerCase().includes(searchClient.toLowerCase()));
    const totalSpent = invs.reduce((s, inv) => s + inv.items.reduce((ss, it) => ss + it.qty * it.price, 0) + (inv.shipping || 50), 0);
    const unpaidInvs = invs.filter(i => i.unpaid);
    const products = {};
    invs.forEach(inv => inv.items.forEach(it => { if (!products[it.title]) products[it.title] = { qty: 0, total: 0 }; products[it.title].qty += it.qty; products[it.title].total += it.price * it.qty; }));
    setCustomerData({ invoices: invs, totalSpent, unpaidInvs, products: Object.entries(products).map(([title, data]) => ({ title, ...data })) });
  }

  function addCustomer() {
    if (!newCustomer.name.trim()) return;
    const updated = [...customers, { ...newCustomer, name: newCustomer.name.trim() }];
    onUpdateCustomers(updated);
    setNewCustomer({ name: "", phone: "", email: "" });
    setShowAddForm(false);
  }

  function deleteCustomer(name) {
    if (!confirm(`Delete customer "${name}"?`)) return;
    onUpdateCustomers(customers.filter(c => c.name !== name));
  }

  return (<div>
    <div style={S.pageTitle}>👥 Customer Portal</div>
    <div style={S.pageSubtitle}>Manage customers, view purchase history and pending invoices.</div>

    {/* Add Customer */}
    <div style={S.card}>
      <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom: showAddForm ? 14 : 0 }}>
        <div style={S.cardTitle}>➕ {showAddForm ? "Add New Customer" : "Customer Management"}</div>
        <button style={S.btn("primary")} onClick={()=>setShowAddForm(!showAddForm)}>{showAddForm ? "Cancel" : "➕ Add Customer"}</button>
      </div>
      {showAddForm && (
        <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr 1fr auto", gap:8, alignItems:"flex-end", background:C.bg, padding:14, borderRadius:8, marginBottom:12 }}>
          <div><label style={S.label}>Customer Name *</label><input style={S.input} value={newCustomer.name} onChange={e=>setNewCustomer({...newCustomer,name:e.target.value})} placeholder="e.g. Avedi"/></div>
          <div><label style={S.label}>Phone</label><input style={S.input} value={newCustomer.phone} onChange={e=>setNewCustomer({...newCustomer,phone:e.target.value})} placeholder="07XX XXX XXX"/></div>
          <div><label style={S.label}>Email</label><input style={S.input} value={newCustomer.email} onChange={e=>setNewCustomer({...newCustomer,email:e.target.value})} placeholder="email@example.com"/></div>
          <button style={S.btn("success")} onClick={addCustomer}>✓ Save</button>
        </div>
      )}
    </div>

    <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:18 }}>
      <div>
        <div style={S.card}>
          <div style={S.cardTitle}>🔍 Search Customer</div>
          <div style={{ display:"flex", gap:8 }}>
            <select style={S.input} value={searchClient} onChange={e => { setSearchClient(e.target.value); if(e.target.value)lookupCustomer(); }}>
              <option value="">-- Select or type --</option>
              {allCustomers.map(c => <option key={c.name} value={c.name}>{c.name}{c.phone ? ` (${c.phone})` : ""}</option>)}
            </select>
            <button style={S.btn("primary")} onClick={lookupCustomer}>Search</button>
          </div>
          {customerData && (
            <div style={{ marginTop:16 }}>
              <div style={{ background:C.blueLight, borderRadius:8, padding:"14px", marginBottom:12 }}>
                <div style={{ fontSize:18, fontWeight:800, color:C.blueDark, marginBottom:8 }}>{searchClient}</div>
                <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:8, fontSize:12 }}>
                  <div><span style={{ color:C.muted }}>Total Purchases:</span> <b>{customerData.invoices.length}</b></div>
                  <div><span style={{ color:C.muted }}>Total Spent:</span> <b>Ksh {customerData.totalSpent.toLocaleString()}</b></div>
                  <div><span style={{ color:C.muted }}>Unpaid Invoices:</span> <b style={{ color: customerData.unpaidInvs.length > 0 ? C.red : C.success }}>{customerData.unpaidInvs.length}</b></div>
                </div>
              </div>
              {customerData.unpaidInvs.length > 0 && (
                <div style={{ marginBottom:12 }}><div style={{ fontWeight:700, color:C.red, fontSize:13, marginBottom:6 }}>⚠️ Pending Invoices:</div>
                  {customerData.unpaidInvs.map(inv => { const tot = inv.items.reduce((s, it) => s + it.qty * it.price, 0) + inv.shipping; const bal = tot - (inv.paid || 0); return (
                    <div key={inv.id} style={{ background:"#fff7ed", padding:"10px 14px", borderRadius:6, marginBottom:6, border:`1px solid ${C.gold}`, display:"flex", justifyContent:"space-between", alignItems:"center" }}>
                      <div><b>#{String(inv.id).padStart(4, "0")}</b> — {inv.date}</div><div style={{ color:C.red, fontWeight:700 }}>Ksh {bal.toLocaleString()}</div>
                    </div>);})}
                </div>
              )}
              {customerData.products.length > 0 && (
                <div><div style={{ fontWeight:700, fontSize:12, marginBottom:6 }}>📚 Purchase History:</div>
                  {customerData.products.map(p => (<div key={p.title} style={{ display:"flex", justifyContent:"space-between", padding:"6px 0", borderBottom:`1px solid ${C.border}`, fontSize:12 }}><span>{p.title} (x{p.qty})</span><span>Ksh {p.total.toLocaleString()}</span></div>))}
                </div>
              )}
            </div>
          )}
        </div>
      </div>
      <div style={S.card}>
        <div style={S.cardTitle}>🏆 All Customers ({allCustomers.length})</div>
        <div style={{ maxHeight:500, overflowY:"auto" }}>
          <table style={S.table}><thead><tr>{["Customer","Phone","Purchases","Total Spent","Unpaid","Last Visit",""].map(h=><th key={h} style={S.th}>{h}</th>)}</tr></thead>
            <tbody>{allCustomers.map(c => (<tr key={c.name} style={{ cursor:"pointer" }} onClick={() => { setSearchClient(c.name); lookupCustomer(); }}>
              <td style={S.td}><b>{c.name}</b></td><td style={S.td}>{c.phone||"—"}</td><td style={S.td}>{c.invoices}</td>
              <td style={S.td}>Ksh {c.totalSpent.toLocaleString()}</td>
              <td style={S.td}>{c.unpaid > 0 ? <span style={{ color:C.red, fontWeight:700 }}>{c.unpaid}</span> : <span style={{ color:C.success }}>0</span>}</td>
              <td style={S.td}>{c.lastVisit||"—"}</td>
              <td style={S.td}><button style={{...S.btn("danger"),padding:"3px 8px",fontSize:10}} onClick={(e)=>{e.stopPropagation();deleteCustomer(c.name);}}>Del</button></td>
            </tr>))}</tbody></table>
        </div>
      </div>
    </div>
  </div>);
}

function UserManagement({ onUsersUpdated }) {
  const [users, setUsers] = useState(getUsers());
  const [showForm, setShowForm] = useState(false);
  const [editingUser, setEditingUser] = useState(null);
  const [form, setForm] = useState({ username:"", password:"", role:"teller", name:"" });
  const [message, setMessage] = useState("");
  function flashMsg(msg) { setMessage(msg); setTimeout(() => setMessage(""), 3000); }
  function handleSave() { if (!form.username || !form.password || !form.name) { flashMsg("Please fill all fields"); return; } const username = form.username.toLowerCase(); const updated = { ...users }; if (!editingUser && updated[username]) { flashMsg("Username already exists"); return; } updated[username] = { password: form.password, role: form.role, name: form.name }; setUsers(updated); saveUsers(updated); onUsersUpdated(updated); setShowForm(false); setEditingUser(null); setForm({ username:"", password:"", role:"teller", name:"" }); }
  function handleDelete(username) { if (username === "admin") { alert("Cannot delete the main admin account!"); return; } if (!confirm(`Delete user "${username}"?`)) return; const updated = { ...users }; delete updated[username]; setUsers(updated); saveUsers(updated); onUsersUpdated(updated); }
  function handleEdit(username) { const user = users[username]; setEditingUser(username); setForm({ username, password: user.password, role: user.role, name: user.name }); setShowForm(true); }
  return (<div style={S.card}><div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:14 }}><div><div style={S.cardTitle}>👥 User Management</div><div style={{ fontSize:12, color:C.muted }}>Manage who can access the system</div></div><button style={S.btn("primary")} onClick={()=>{setEditingUser(null);setForm({username:"",password:"",role:"teller",name:""});setShowForm(!showForm);setMessage("");}}>{showForm?"Cancel":"➕ Add User"}</button></div>{message && <div style={{ background:message.includes("success")?C.successBg:"#fee2e2", color:message.includes("success")?C.success:C.red, padding:"8px 14px", borderRadius:7, marginBottom:12, fontSize:12, fontWeight:600 }}>{message}</div>}{showForm && (<div style={{ background:C.bg, borderRadius:10, padding:"16px", marginBottom:14, display:"grid", gridTemplateColumns:"1fr 1fr 1fr 1fr auto", gap:10, alignItems:"flex-end" }}><div><label style={S.label}>Username *</label><input style={S.input} placeholder="e.g. johndoe" value={form.username} disabled={editingUser!==null} onChange={e=>setForm({...form,username:e.target.value})}/></div><div><label style={S.label}>Password *</label><input style={S.input} type="text" placeholder="Password" value={form.password} onChange={e=>setForm({...form,password:e.target.value})}/></div><div><label style={S.label}>Full Name *</label><input style={S.input} placeholder="e.g. John Doe" value={form.name} onChange={e=>setForm({...form,name:e.target.value})}/></div><div><label style={S.label}>Role</label><select style={S.input} value={form.role} onChange={e=>setForm({...form,role:e.target.value})}><option value="teller">Teller</option><option value="admin">Admin</option></select></div><button style={S.btn("success")} onClick={handleSave}>{editingUser?"✓ Update":"➕ Add"}</button></div>)}<table style={S.table}><thead><tr>{["Username","Full Name","Role","Password","Actions"].map(h=><th key={h} style={S.th}>{h}</th>)}</tr></thead><tbody>{Object.entries(users).map(([username,user])=>(<tr key={username}><td style={S.td}><b>{username}</b></td><td style={S.td}>{user.name}</td><td style={S.td}><span style={S.badge(user.role==="admin"?"purple":"green")}>{user.role==="admin"?"👑 Admin":"💳 Teller"}</span></td><td style={S.td}><code style={{background:C.bg,padding:"2px 8px",borderRadius:4,fontSize:11}}>{user.password}</code></td><td style={S.td}><div style={{display:"flex",gap:5}}><button style={{...S.btn("ghost"),padding:"4px 10px",fontSize:11}} onClick={()=>handleEdit(username)}>✏️ Edit</button>{username!=="admin"&&<button style={{...S.btn("danger"),padding:"4px 10px",fontSize:11}} onClick={()=>handleDelete(username)}>🗑️ Delete</button>}</div></td></tr>))}</tbody></table></div>);
}

